import fs from 'fs-extra';
import path from 'path';
import expandHomeDir from 'expand-home-dir';
import EventEmitter from 'events';

import FormatHelper from './format-helper';

let loggingToFiles = {};  // index of all files being logged to


class FileBackend extends EventEmitter {  // gets original arguments
    constructor(filename=null, directory=null) {
        super();
        this.filename = filename;
        this.directory = directory;
        this.file = undefined;

        if (!this.filename) {
            let timestamp = new Date().toISOString();
            if (process.platform === 'win32') {
                // replace all ':'s for '_'s as windows file paths cannot have that character in them
                timestamp = timestamp.replace(/:/g, '_');
            }
            this.filename = 'skill.' + timestamp + '.log';
        }

        if (!this.directory && !path.isAbsolute(this.filename)) {
            // see if we are running on robot
            if (process.platform === 'linux' && process.arch === 'arm' && fs.existsSync('/var/jibo')) {
                this.directory = '/var/jibo/logs';
            } else {
                this.directory = expandHomeDir('~/jibo/logs');
            }
        }
    }


    init(callback=null) {

        this.createDirectory( () => {
            let fullFilename = path.normalize(this.filename);
            if (!path.isAbsolute(fullFilename)) {
                fullFilename = path.join(this.directory, fullFilename);
            }
            fullFilename = path.resolve(fullFilename);

            if (!loggingToFiles[fullFilename]) {
                loggingToFiles[fullFilename] = this;
                console.log('jibo.log: logging to', fullFilename);
                this.file = fs.createWriteStream(fullFilename, {'flags': 'a'});  // append
            } else {
                console.log('jibo.log: already logging to', fullFilename);
            }

            if (callback) {
                callback();
            }
        });
    }


    write(name, level, args) {
        let timestamp = new Date().toISOString();
        let text = FormatHelper(args);
        let message = timestamp + ' '
                + (name ? name + ' ' : '')
                + (level ? level + ' ' : '')
                + text;

        this.file.write(message + '\n');
    }


    createDirectory(callback) {
        if (this.directory && !path.isAbsolute(this.filename)) {
            fs.ensureDir(this.directory, (err) => {
                if (err) {
                    console.error('jibo.log: error creating directory', this.directory, err);
                }
                callback();
            });
        } else {
            setImmediate(callback);
        }
    }
}


export default FileBackend;




